rust_stack.example:
 // src/features/create_post/mod.rs
use axum::{extract::State, Json, response::IntoResponse};
use serde::Deserialize;
use validator::Validate;
use std::sync::Arc;
use thiserror::Error;
use tracing::instrument;
use anyhow::Context;
#[derive(Deserialize, Validate)]
#[serde(deny_unknown_fields)]
pub struct CreatePostCommand {
#[validate(length(min = 1, max = 200))]
pub title: String,
#[validate(length(min = 1))]
pub content: String,
}
#[derive(Debug)]
pub struct Post {
pub title: String,
pub content: String,
}
impl Post {
pub fn new(title: String, content: String) -> Self {
Self { title, content }
}
}
#[instrument(skip_all)]
pub async fn handler(
State(repo): State<Arc<dyn PostRepository>>,
Json(cmd): Json<CreatePostCommand>,
) -> Result<impl IntoResponse, AppError> {
cmd.validate().map_err(AppError::Validation)?;
let post = Post::new(cmd.title, cmd.content);
let id = repo.save(post)
.await
.context("Failed to save post")?;
Ok(Json(id))
}
#[async_trait::async_trait]
pub trait PostRepository: Send + Sync + 'static {
async fn save(&self, post: Post) -> Result<i32, anyhow::Error>;
}

testing_strategies.example:
 #[cfg(test)]
mod tests {
use super::*;
use mockall::mock;
use anyhow::Result as AnyResult;
mock! {
pub PostRepository {}
#[async_trait::async_trait]
impl PostRepository for PostRepository {
async fn save(&self, post: Post) -> AnyResult<i32>;
}
}
#[tokio::test]
async fn handle_valid_command_returns_post_id() {
let mut mock_repo = MockPostRepository::new();
mock_repo.expect_save().returning(|_| Ok(42));
let cmd = CreatePostCommand {
title: "Title".to_string(),
content: "Content".to_string()
};
let result = handler(State(Arc::new(mock_repo)), Json(cmd)).await;
assert!(result.is_ok());
}
}
